keyframes.cssText:
@keyframes balancedEffect { 
  0% { transform: rotate(0deg); }
  50% { transform: rotate(20deg); }
  100% { transform: rotate(0deg); }
}

@keyframes revealAnimation { 
  0% { opacity: 0; transform: translateY(80px); }
  100% { opacity: 1; transform: translateY(0px); }
}

@keyframes topBannerAnimation { 
  0% { background-position: 0px 50%; background-size: 400% 400%; }
  50% { background-position: 33% 50%; background-size: 400% 400%; }
  100% { background-position: 66% 50%; background-size: 400% 400%; }
}

@keyframes halo-bottom-animation { 
  0% { opacity: 0; transform: translateY(8px); }
  100% { opacity: 1; transform: translateY(0px); }
}

@keyframes move-1 { 
  0% { transform: translate3d(-2px, -6px, -9px); }
  25% { transform: translate3d(2px, 0px, 10px); }
  75% { transform: translate3d(-3px, 3px, 5px); }
  100% { transform: translate3d(-2px, -6px, -9px); }
}

@keyframes move-2 { 
  0% { transform: translate3d(-3px, 3px, -3px); }
  25% { transform: translate3d(1px, 5px, -7px); }
  50% { transform: translateZ(0px); }
  75% { transform: translate3d(-5px, -4px, 4px); }
  100% { transform: translate3d(-3px, 3px, -3px); }
}

@keyframes move-3 { 
  0% { transform: translateZ(0px); }
  35% { transform: translate3d(5px, -4px, 8px); }
  65% { transform: translate3d(-8px, -7px, -15px); }
  100% { transform: translateZ(0px); }
}

@keyframes move-4 { 
  0% { transform: translate3d(2px, 5px, -3px); }
  35% { transform: translateZ(0px); }
  65% { transform: translate3d(-3px, -2px, -5px); }
  100% { transform: translate3d(2px, 5px, -3px); }
}

@keyframes spinner-kk2y8v { 
  0% { transform: rotate(0deg); }
  10%, 15% { transform: rotate(-90deg); }
  20%, 25% { transform: rotate(-180deg); }
  30%, 35% { transform: rotate(-270deg); }
  40%, 50% { transform: rotate(-1turn); }
  100% { transform: rotate(2turn); }
}
